var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관 본부</color> 라운드 테이블","JPN":"<color=#ffd34c>プリドウェン機関本部</color>ラウンドテーブル","ENG":"<color=#ffd34c>Prydwen Institution HQ</color> Round Table","TWN":"<color=#ffd34c>普利多溫機關總部</color> 圓桌會議"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"기관장님! LAKE-9에 침입한 학회원을 모두 제압 완료하였습니다!","JPN":"機関長！　LAKE-9に侵入した学会員を全員制圧しました！","ENG":"Chief! We subdued all Society members that invaded LAKE-9!","TWN":"機關長！侵入LAKE-9的學會成員已全部制服！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"LAKE-2도 제압 완료하였습니다!","JPN":"LAKE-2も制圧完了です！","ENG":"LAKE-2 is complete as well!","TWN":"LAKE-2也制服完畢！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다들 수고하셨어요.","JPN":"皆さん、お疲れさまでした。","ENG":"Good work, everyone.","TWN":"你們辛苦了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"학회에게 습격받은 시설 일곱 곳 중에서 이제 남은 건 LAKE-4, LAKE-7, LAKE-11.","JPN":"学会から襲撃された施設7カ所のうち、残ったのはLAKE-4、LAKE-7、LAKE-11。","ENG":"Out of the seven facilities that the Society ambushed, LAKE-4, LAKE-7, and LAKE-11 are still in battle.","TWN":"學會襲擊的七個設施中，現在剩下的是LAKE-4，LAKE-7，LAKE-11。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"세 곳이군요.","JPN":"3カ所ですわね。","ENG":"Three facilities.","TWN":"這三個地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"기관장님. 선택하셔야 합니다.","JPN":"機関長。今こそ決断を下す時です。","ENG":"Chief, you must make a decision.","TWN":"機關長，你需要抉擇。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"카운터 요원들이 빠진 지금, 남은 봉인 시설을 전부 보호하는 것은 무리입니다.","JPN":"カウンターがいない今、残りの封印施設をすべて保護することは不可能です。","ENG":"Without the Counter agents, we won't be able to protect all the remaining quarantine facilities.","TWN":"制裁者特工們如今不在，想要保護剩下的所有封印設施未免太勉強了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"LAKE-4의 경우, 지난 학회의 공격에서 받은 피해를 아직 완전히 수복하지 못했습니다.","JPN":"LAKE-4の場合、この前の学会の攻撃で受けた被害をまだ完全に修復できていません。","ENG":"In the case of LAKE-4, they haven't fully recovered from the last attack from the Society.","TWN":"而且LAKE-4，尚未完全恢復上次學會攻擊後受到的損失。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"봉인된 파편 역시 학회와 엘리시움 연합으로 인해 상당히 소모되었죠.","JPN":"封印された破片もまた、学会とエリシウム連合のせいで相当数を消耗しました。","ENG":"The sealed Fragment was consumed quite a bit because of the alliance between the Society and Elysium.","TWN":"封印的碎片也因學會和愛樂組織的聯手消耗了很多。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"다른 봉인 시설에 비해 전략적 가치가 떨어집니다.","JPN":"他の封印施設に比べ、戦略的な価値は低いです。","ENG":"Its strategic value is less than the other quarantine facilities.","TWN":"與其他封印設施相比，戰略價值較低。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이번에야 말로, LAKE-4에 붕괴 조치를 취하자는 뜻이로군요.","JPN":"今度こそ、LAKE-4を崩壊措置しようという話ですね？","ENG":"You wish to have LAKE-4 destroyed with this opportunity.","TWN":"你的意思是，趁這次機會對LAKE-4採取瓦解措施。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"시간이 없습니다!","JPN":"時間がありません！","ENG":"We don't have time!","TWN":"沒時間了！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"녀석들에게 파편을 빼앗길 바에야, 파편과 함께 생매장시키는 편이 낫지 않습니까?","JPN":"やつらに破片を奪われるくらいなら、破片ごと生き埋めにした方がいいのでは？","ENG":"Isn't it better to bury them alive with the Fragment rather than for them to seize it?","TWN":"與其被他們搶走碎片，還不如把他們和碎片一起埋到地下！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"그곳의 기관원들도 기꺼이 희생을 감수할 것입니다.","JPN":"あそこの機関員も、喜んで犠牲を受け入れるでしょう。","ENG":"I'm sure the members there will be glad to offer their lives for the cause.","TWN":"那裡的機關成員也甘願犧牲。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"부디 용단을 내려주십시오, 기관장님!","JPN":"どうかご英断を、機関長！","ENG":"I hope you make the right decision, Chief!","TWN":"務請決斷，機關長！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"최고등급 재난경보, 고고학부장의 탈옥, 봉인 시설의 습격…….","JPN":"最高ランクの災難警報、考古学部長の脱獄、封印施設の襲撃……","ENG":"The highest-level disaster alert, the Dean of Archeology breaking out, and the ambush on the quarantine facilities...","TWN":"最高級別的災難警報，考古學教授的越獄，封印設施的襲擊……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"클리포트 게임이 끝난 지 얼마 지나지 않았는데, 기관에는 악재가 겹치는군요.","JPN":"クリフォトゲームが終わって間もないのに、機関には厄災が耐えませんわ。","ENG":"It hasn't been that long since the Qliphoth Game ended, but the Institution is experiencing one bad luck after another.","TWN":"逆卡巴拉遊戲才結束沒多久，機關就接二連三地出現危機。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼에도 선택을 피해서는 안 되겠죠.","JPN":"それでも、選択は避けられません。","ENG":"But still, I cannot avoid making a decision.","TWN":"即便如此，我們也不能回避選擇。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"LAKE-4에 있는 전 인원에게 퇴거 조치 명령을 내리세요!","JPN":"LAKE-4にいるすべての人員に、退去措置命令を出しなさい！","ENG":"Instruct all members at LAKE-4 to evacuate!","TWN":"請向LAKE-4的所有人員下達撤退命令！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관</color> 비밀 격리 시설 LAKE-4","JPN":"<color=#ffd34c>プリドウェン機関</color>の秘密隔離施設 LAKE-4","ENG":"<color=#ffd34c>Prydwen Institution</color> Secret Quarantine Facility LAKE-4","TWN":"<color=#ffd34c>普利多溫機關</color> 秘密隔離設施LAKE-4"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"대장님! 퇴거 명령이 떨어졌습니다!","JPN":"隊長！　退去命令が出されました！","ENG":"Commander! We received orders to evacuate!","TWN":"隊長！收到了撤退命令！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L44_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"현 시간부로 LAKE-4는 붕괴합니다! 어서, 어서! 섬 밖으로 대피하셔야 합니다!","JPN":"現時間をもって、LAKE-4は崩壊します！　早く、早く！　島の外に待避してください！","ENG":"LAKE-4 will be collapsing from here on out! We have to make haste! We must evacuate the island!","TWN":"從現在開始，LAKE-4即將瓦解！要盡快！躲避到島外！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"먼저 가라.","JPN":"先に行け。","ENG":"Go ahead.","TWN":"你們先走吧。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"네? 그게 무슨 소리입니까!","JPN":"はい？　それはいったい！","ENG":"Excuse me? I don't understand!","TWN":"嗯？你在說什麼！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"누군가는 여기 남아서 학회 녀석들의 발을 묶어 놔야 해.","JPN":"誰かはここに残って学会のやつら相手に時間稼ぎをしないとな。","ENG":"Someone has to stay here and hold those Society wretches in place.","TWN":"總得有人留在這裡，擋住學會的去路。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"또 누군가는, 이곳에 남아서 기밀과 정보들을 소각해야겠지.","JPN":"そしてもう一人は、ここに残って機密と情報を焼却する。","ENG":"Also, someone has to stay here and get rid of all the information and documents.","TWN":"還要有人，留在這裡銷毀機密情報。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 누군가는…….","JPN":"そしてまたもう一人は……","ENG":"And someone...","TWN":"還有……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"저 빌어먹을 학회 녀석들이 매장당하는 순간을 끝까지 지켜봐야만 해.","JPN":"あのクソ学会のやつらが生き埋めにされる瞬間を、見届けないと。","ENG":"has to stay here and watch the bloody Society monsters get buried alive.","TWN":"我要好好看著那幫該死的學會被埋葬的那一刻……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"어떻게 살려고 발버둥치는지, 얼마나 고통스러워하는지……!","JPN":"生き残るため足掻き、苦しむ姿を……！","ENG":"Everything, their struggles and their pain...!","TWN":"看他們掙扎著想活下去，痛苦的嘴臉……！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그래야 이 희생이 의미가 있어.","JPN":"それでこそ、この犠牲に意味があるんだ。","ENG":"Or else this sacrifice won't mean anything.","TWN":"只有這樣，這個犧牲才有意義。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장님께서도 다 감수하시고, 이런 명령을 내리시는 거다.","JPN":"機関長も全て承知の上で、命令を出したのだよ。","ENG":"Chief has already taken this into consideration as she gave this order.","TWN":"機關長也甘願承受，所以才下達了這樣的命令。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 빨리 먼저 가!","JPN":"だから、早く先に行け！","ENG":"So hurry up and leave!","TWN":"所以，快點先走吧！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"제기랄! 장난해요!?","JPN":"くそっ！　ふざけないでください！！","ENG":"Bloody hell! Are you kidding?!","TWN":"該死！你在開玩笑嗎？！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"말이나 말지! 그런 소리까지 듣고 어떻게 두고 도망칩니까!","JPN":"こんな話、聞きたくなかった……！　そんなことを言われて、逃げられるはずないでしょう！","ENG":"You could've spared me the speech! Now there's no way I can run away after hearing all that!","TWN":"還不如不說呢！聽到這些話後，我們怎麼能丟下你跑掉呢！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워! 빨리 여기서……!","JPN":"うるさい！　早くここから……！","ENG":"Shut it! Quickly, get out–","TWN":"吵死了！快點從這裡……！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"커헉!!","JPN":"ガハッ！！","ENG":"Kgh!!","TWN":"咳！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 이건……!?","JPN":"な、何だ？　これは……？","ENG":"W-what? This...?!","TWN":"怎，怎麼回事？這是……？！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"순식간에 몸이……?","JPN":"一瞬で体が……？","ENG":"My body just split in–?","TWN":"一瞬間身體就……？"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"쉽군…….","JPN":"簡単だ……","ENG":"Easy....","TWN":"太容易了……"},"stage":{"bg":"PRYDWEN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"너희들의 생각은 질려버릴 정도로 읽기 쉬워.","JPN":"お前らの考えは、見え透いている。","ENG":"Your minds are so easy to predict it's almost tiring.","TWN":"你們的想法太容易被識破了。"},"stage":{"bg":"PRYDWEN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"지금이다. 어머니의 자녀들이여.","JPN":"今だ。母の子どもたちよ。","ENG":"Now, Mother's children.","TWN":"就是現在，母親的子女們啊。"},"stage":{"bg":"PRYDWEN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"시설의 봉인 사슬을 끊고, 파편을 폭주시켜라!","JPN":"施設の封印の鎖を切り、破片を暴走させろ！","ENG":"Break the Sealing Chains in the facility and erupt the Fragment!","TWN":"解除設施的封印鎖鏈，讓碎片暴走吧！"},"stage":{"bg":"PRYDWEN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"지휘관님! A-3 구역에서 이상 사태가 발생!","JPN":"指揮官！　A-3区域で異常状態が発生！","ENG":"Commander! We've received concerning news from Area A-3!","TWN":"指揮官！A-3區域發生異常情況！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"라운드 테이블에서 보고받은 요주의 인물과 인상착의가 똑같습니다!","JPN":"ラウンドテーブルで報告を受けた要注意人物と一致します！","ENG":"It has the same features and outfits as the person of interest that was mentioned at the Round Table!","TWN":"和圓桌會議上報告的需要注意的人物有著一模一樣的衣著！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"녀석과 그 신자로 보이는 자들이 봉인 사슬을 해제하고 있습니다.","JPN":"やつとその信徒と見られる者たちが、封印の鎖を解除しています。","ENG":"He and the followers are dismantling the Sealing Chains.","TWN":"那傢伙和看起來像其信徒的人正在解除封印鎖鏈。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"파편 활성화 반응 34%……! 43%!","JPN":"破片活性化反応34％……！　43％！","ENG":"Fragment is 34% activated...! Going up to 43%!","TWN":"碎片啟動反應34%……！43%！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"계속 증가하고 있습니다! 이대로라면……!","JPN":"増加しています！　このままでは……！","ENG":"It's increasing! At this rate...!","TWN":"一直在增加！照這樣下去……！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"제기랄! 퇴거 조치까지 기다려주지도 않는 건가!","JPN":"くそ！　退去措置が終わるまで待ってもくれないのか！","ENG":"Bollocks! We won't even have enough time to evacuate!","TWN":"該死！連撤退都等不到了嗎！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"이러다간 파편을 빼앗기겠어! 당장 붕괴시켜야만 해!","JPN":"このままでは破片を奪われる！　今すぐ崩壊させないと！","ENG":"We're going to lose the Fragment! We have to destroy the facility, now!","TWN":"再這樣下去，碎片會被搶走的！必須馬上執行瓦解指令！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"여기는 통제실!","JPN":"こちら、統制室！","ENG":"This is control room!","TWN":"這裡是控制室！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"기관장님, 저희는 당장이라도 녀석들을 생매장해 버릴 준비가 됐습니다.","JPN":"機関長、俺たちは今すぐにでもやつらを生き埋めにする準備ができています。","ENG":"Chief, we are ready to bury them alive at any moment.","TWN":"機關長，我們已經準備好把敵人活埋了。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"알겠습니다. 기관은 여러분의 희생을 잊지 않을 겁니다.","JPN":"わかりました。機関は皆さんの犠牲を忘れません。","ENG":"Very well. The Institution will not forget your noble sacrifice.","TWN":"知道了。機關不會忘記你們的犧牲。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"현 시간부로 LAKE-4는 붕괴 조치를 취합니다.","JPN":"現時間をもって、LAKE-4は崩壊措置に入ります。","ENG":"From here on end, LAKE-4 will be entering complete destruction.","TWN":"從現在起，LAKE-4將啟動瓦解計畫。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 책임은……!","JPN":"その責任は……！","ENG":"And the responsibility...!","TWN":"這個責任……！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"모두 제가 짊어지겠어요.","JPN":"すべて私が持ちますわ。","ENG":"will be all mine to shoulder.","TWN":"全部由我來承擔。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"명령 받들겠습니다, 기관장님!","JPN":"承知しました、機関長！","ENG":"Orders received, Chief!","TWN":"遵命，機關長！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"LAKE-4 붕괴 조치! 모든 폭발물을 격발시킨다!","JPN":"LAKE-4、崩壊措置！　すべての爆発物を撃発させる！","ENG":"Destroy LAKE-4! Detonate all explosives!","TWN":"LAKE-4瓦解計畫！引爆所有爆炸物！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"격발!","JPN":"撃発！","ENG":"Detonate!","TWN":"引爆！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"LAKE-4 붕괴 조치 완료.","JPN":"LAKE-4崩壊措置完了。","ENG":"LAKE-4 has been destroyed.","TWN":"LAKE-4瓦解計畫完畢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"파편 활성화 0% 확인된 생명 반응…… 없습니다.","JPN":"破片活性化0％、確認された生命反応……ありません。","ENG":"Fragment is at 0%, and no... lifeforms detected.","TWN":"碎片活性幾乎為0%，無任何……生命反應。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"모두 고생하셨습니다.","JPN":"みなさん、お疲れさまでした。","ENG":"Good work everyone.","TWN":"大家都辛苦了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이제 다음 봉인 시설의 지휘권을…….","JPN":"では、次の封印施設の指揮権を……","ENG":"And I'll be giving the commanding power of the next quarantine facility to–","TWN":"接下來，連同下一個封印設施的指揮……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"기, 기관장님……?","JPN":"き、機関長……？","ENG":"C-chief...?","TWN":"機，機關長……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"소실된 LAKE-4으로부터…… 지휘관 라인으로 통신이 들어왔습니다.","JPN":"消失されたLAEK-4から……指揮官ラインに通信が入りました。","ENG":"We received comms from the commander line... of the lost LAKE-4.","TWN":"從消失的LAKE-4……發來了指揮官的通訊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그게 무슨 소리죠?","JPN":"どういうことです？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"파…… 파편을…….","JPN":"は……破片を……","ENG":"The F-Fragment...","TWN":"碎……碎片……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"그 거대한 파편을 순식간에…… 흡수했다고……?","JPN":"あの巨大な破片を、一瞬で……吸収した……？","ENG":"You swallowed the giant Fragment... in an instant...?","TWN":"巨大的碎片瞬間就……被吸收了……？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NPC_NULL","text":{"KOREA":"너, 너는 대체…… 기관장님께 알려야……!!","JPN":"お、お前はいったい……機関長に知らせないと……！！","ENG":"W-what are you... I need to warn Chief...!!","TWN":"你，你到底……必須告訴機關長……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"이건 잠시 빌리도록 하지.","JPN":"これはしばらく借りるとしよう。","ENG":"I'll be borrowing this.","TWN":"這個借我用一下。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"……역시.","JPN":"……やはり。","ENG":"...Just as I thought.","TWN":"……果然。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"예상은 했지만, 역시 흥미롭군.","JPN":"予想はしていたが、興味深い。","ENG":"I had expected as much, but it is still interesting.","TWN":"雖然有預料到，但還是很有趣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"이 세계에서도 또 한 번 사람들을 이끄는가.","JPN":"この世界でも、また人々を導いているのか。","ENG":"You are leading people in this world as well.","TWN":"在這個世界裡也引領著人們嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"그리고 또다시 내 앞에서 대의를 위해 소를 저버리는가.","JPN":"そして、また俺の目の前で大儀のため小を犠牲にするのか。","ENG":"And you would sacrifice the small for the greater cause, once again.","TWN":"然後又在我面前，為了大局犧牲小我嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"팬드래건의 후예여.","JPN":"ペンドラゴンの末裔よ。","ENG":"Heir of Pendragon.","TWN":"潘德拉貢的後裔。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제가 유명하다는 건, 저도 잘 알고 있습니다만.","JPN":"私が有名人であることは、私自身も存じておりますが……","ENG":"I am well aware that I'm famous.","TWN":"我很清楚這個姓氏有多出名。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"누구신지도 모를 분이 함부로 저희 가문을 들먹이다니, 몹시 불쾌하군요.","JPN":"名前も知らないお方にそう容易く我が家門の名を口にされると、とても不快ですわね。","ENG":"But it is very disturbing to hear my family's name being uttered by a complete stranger.","TWN":"但聽到身分不明的人隨便議論我的家族，真是讓人不快。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"라이언을 쓰러트렸다는 거짓된 신의 숭배자가 당신인가요?","JPN":"ライアンを倒したという偽りの神の崇拝者とは、あなたのことですか？","ENG":"Are you the worshipper of the false god that defeated Ryan?","TWN":"把瑞安打倒的假神崇拜者就是你嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"라이언? 아아, 그래. 잘 훈련된 사냥개더군.","JPN":"ライアン？　ああ、そうか。よく躾けられた猟犬だったよ。","ENG":"Ryan? Ahh, right. He was a well-trained hound.","TWN":"瑞安？啊啊，是啊，確實是個訓練有素的獵犬。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"덕분에 꽤나 결투를 즐길 수 있었지.","JPN":"おかげで、随分楽しませてもらった。","ENG":"I was able to enjoy the fight thanks to him.","TWN":"多虧於此，我很享受。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"헛소리는 거기까지 하시죠.","JPN":"戯言はそこまでにしてください。","ENG":"Enough nonsense.","TWN":"廢話就到此為止吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신들이 무슨 목적으로 이런 짓을 벌이는지는 모르겠지만.","JPN":"あなたたちが何の目的でこのようなことをしているのかはわかりませんが……","ENG":"I do not know for what reason you are doing this,","TWN":"雖然不知道你們這麼做是為了什麼。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"학회에서도 인정받지 못한 사교도들 주제에 기관과 전면전을 벌일 생각인가요?","JPN":"学会からも認められていない邪教徒の分際で、機関と全面戦争をするおつもりで？","ENG":"but you're cultists who haven't even been recognized by the Society. Do you really wish to wage a full-scale war on the Institution?","TWN":"區區在學會都沒有得到認可的異教徒，還想和機關開啟全面戰爭？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대답이 없으시군요.","JPN":"返事がありませんわね。","ENG":"Not willing to answer, I see.","TWN":"你為什麼不回答我。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 자기 변호를 할 수 있는 마지막 기회를 드리겠습니다.","JPN":"では、最後に自己弁護する機会を与えましょう。","ENG":"Then, here is your last chance to defend yourself.","TWN":"那麼，我給你最後一次機會為自己辯護。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"LAKE-4에 봉인되어 있던 파편은 지금 어디 있죠?","JPN":"LAKE-4に封印されていた破片は、今どこにあるのですか？","ENG":"Where is the Fragment that was sealed at LAKE-4?","TWN":"LAKE-4裡封印的碎片現在在哪裡？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"후후. 확실히.","JPN":"ふふ。確かに。","ENG":"Hah hah. Of course.","TWN":"呵呵，確實。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"지금 우리들의 세력으로는, 기관과의 전면전을 펼치는 건 무리겠지.","JPN":"今俺たちの勢力では、機関との全面戦争は無理だろう。","ENG":"It would be unwise to go on a full-scale war with the Institution considering the number of people we currently have.","TWN":"以我們現在的勢力，跟機關打一場全面戰是有些牽強的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"하지만 나는 지겹도록 너희의 방식을 잘 알고 있다.","JPN":"だが、俺はお前たちのやり方をうんざりするほどよく知っている。","ENG":"But I am so fully aware of the way you do.","TWN":"但是我非常了解你們的方式。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"방식이라고?","JPN":"やり方ですって？","ENG":"The way we do?","TWN":"方式？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 다른 시설을 일제히 공격한 것이…….","JPN":"では、他の施設を一斉に攻撃したのは……","ENG":"Then your attacking different facilities at once is...","TWN":"那麼同時攻擊了其他設施是因為……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"너희라면 다른 시설을 지키기 위해…… 반드시 이곳을 희생시키리라 생각했다.","JPN":"お前たちなら、他の施設を守るために……必ずここを犠牲にすると思った。","ENG":"I thought that you would sacrifice this place... to protect the other facilities.","TWN":"我想你們會為了守護其他設施……一定會犧牲這個地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"대를 위해서, 가차없이 소를 잘라내는 너희들이라면 말이야.","JPN":"大のために、容赦なく小を切り捨てるお前たちならな。","ENG":"After all, you always mercilessly sacrifice the little people for the greater good.","TWN":"只要是為了大局，你們便會毫不留情地砍掉小我。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"하지만 우리 목표는 처음부터 이곳이었어.","JPN":"だが、俺たちの目標は最初からここだったぞ。","ENG":"But this place was our goal from the start.","TWN":"但是我們的目標從一開始就是這裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"이 정도 파편이라면, 어머니를 깨우기 위한 밑준비로는 충분하니까.","JPN":"この程度の破片なら、お母さんを目覚めさせるための下準備としては十分だ。","ENG":"This Fragment is enough to make preparations for waking Mother.","TWN":"這些碎片，足以喚醒母親。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"어머니……?","JPN":"お母さん……？","ENG":"Mother...?","TWN":"母親……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"어머니께서는 지식의 호수가 하나되기를 바라신다.","JPN":"お母さんは、知識の湖が一つになることをお望みだ。","ENG":"Mother wishes the Lake of Knowledge to be one.","TWN":"母親希望知識湖水合而為一。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_SHADOW","text":{"KOREA":"그리고…… 내가 그것을 실현시킬 것이다.","JPN":"そして……俺がそれを実現させる。","ENG":"And... I will make it happen.","TWN":"還有……我會實現它。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"아무리 너라도 내 앞을 가로막을 생각이라면…… 나는 주저없이 널 죽이겠다.","JPN":"いくらお前でも、俺の邪魔をするつもりなら……俺は躊躇なくお前を殺す。","ENG":"And if you are to stand in my way... I will kill you without a second thought.","TWN":"就算是你，如果想擋在我面前……我也會毫不猶豫地殺了你。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"팬드래건의 후예여.","JPN":"ペンドラゴンの末裔よ。","ENG":"Heir of Pendragon.","TWN":"潘德拉貢的後裔啊。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};